import{_ as l,c as e,o as i,ah as r}from"./chunks/framework.Cnj7lwEt.js";const g=JSON.parse('{"title":"pentagi","description":"","frontmatter":{},"headers":[],"relativePath":"github汇总/安全工具/pentagi-安全工具.md","filePath":"github汇总/安全工具/pentagi-安全工具.md"}'),o={name:"github汇总/安全工具/pentagi-安全工具.md"};function t(n,a,h,c,s,p){return i(),e("div",null,a[0]||(a[0]=[r('<h1 id="pentagi" tabindex="-1">pentagi <a class="header-anchor" href="#pentagi" aria-label="Permalink to “pentagi”">​</a></h1><h2 id="项目名称" tabindex="-1">项目名称 <a class="header-anchor" href="#项目名称" aria-label="Permalink to “项目名称”">​</a></h2><p>pentagi</p><h2 id="作者或组织名" tabindex="-1">作者或组织名 <a class="header-anchor" href="#作者或组织名" aria-label="Permalink to “作者或组织名”">​</a></h2><p>vxcontrol</p><h2 id="项目类别" tabindex="-1">项目类别 <a class="header-anchor" href="#项目类别" aria-label="Permalink to “项目类别”">​</a></h2><p>安全工具</p><h2 id="核心痛点" tabindex="-1">核心痛点 <a class="header-anchor" href="#核心痛点" aria-label="Permalink to “核心痛点”">​</a></h2><p>传统渗透测试需要大量人工操作和专业知识，门槛高、效率低。</p><h2 id="主要功能" tabindex="-1">主要功能 <a class="header-anchor" href="#主要功能" aria-label="Permalink to “主要功能”">​</a></h2><p>AI驱动的自动化渗透测试工具，在隔离的Docker沙箱环境中自主执行安全测试。内置20多种专业安全工具（nmap、metasploit、sqlmap等）。支持智能记忆系统，长期存储研究结果。集成知识图谱（Neo4j）、网络情报收集、外部搜索系统。支持10多种大语言模型提供商（OpenAI、Anthropic、Google AI、Ollama、DeepSeek等）。提供REST和GraphQL API，支持Bearer令牌认证。包含Grafana/Prometheus监控和详细报告生成。</p><h2 id="项目亮点" tabindex="-1">项目亮点 <a class="header-anchor" href="#项目亮点" aria-label="Permalink to “项目亮点”">​</a></h2><ul><li>完全自主的AI驱动渗透测试</li><li>Docker沙箱隔离，安全可控</li><li>内置20多种专业安全工具</li><li>智能记忆系统和知识图谱</li><li>支持多种LLM提供商</li><li>可完全本地化部署</li><li>提供完整的REST和GraphQL API</li></ul><h2 id="荣誉信息" tabindex="-1">荣誉信息 <a class="header-anchor" href="#荣誉信息" aria-label="Permalink to “荣誉信息”">​</a></h2><p>README/仓库信息中未明确说明</p><h2 id="项目地址" tabindex="-1">项目地址 <a class="header-anchor" href="#项目地址" aria-label="Permalink to “项目地址”">​</a></h2><p><a href="https://github.com/vxcontrol/pentagi" target="_blank" rel="noreferrer">https://github.com/vxcontrol/pentagi</a> <a href="/网络环境.html">海外网络环境配置 →</a></p><h2 id="安装或部署教程" tabindex="-1">安装或部署教程 <a class="header-anchor" href="#安装或部署教程" aria-label="Permalink to “安装或部署教程”">​</a></h2><h3 id="教程适用对象与环境范围" tabindex="-1">教程适用对象与环境范围 <a class="header-anchor" href="#教程适用对象与环境范围" aria-label="Permalink to “教程适用对象与环境范围”">​</a></h3><p>本教程适用于想要部署和使用PentAGI进行自动化渗透测试的安全专业人员。</p><h3 id="前置条件检查" tabindex="-1">前置条件检查 <a class="header-anchor" href="#前置条件检查" aria-label="Permalink to “前置条件检查”">​</a></h3><ol><li><p><strong>检查Docker是否安装</strong></p><ul><li>执行命令：<code>docker -v</code></li><li>通过标准：显示Docker版本号</li></ul></li><li><p><strong>检查Docker Compose是否安装</strong></p><ul><li>执行命令：<code>docker compose version</code></li><li>通过标准：显示Docker Compose版本号</li></ul></li><li><p><strong>检查系统资源</strong></p><ul><li>执行命令：无命令行检查</li><li>通过标准：至少8GB内存，20GB磁盘空间</li></ul></li></ol><h3 id="主路径-docker-compose部署" tabindex="-1">主路径：Docker Compose部署 <a class="header-anchor" href="#主路径-docker-compose部署" aria-label="Permalink to “主路径：Docker Compose部署”">​</a></h3><p><strong>步骤1：克隆项目</strong></p><ul><li>目标：获取项目源码</li><li>位置：本地目录</li><li>命令：<code>git clone https://github.com/vxcontrol/pentagi.git</code></li><li>成功标志：项目目录创建成功</li><li>失败处理：检查网络连接 <a href="/网络环境.html">海外网络环境配置 →</a></li></ul><p><strong>步骤2：配置环境变量</strong></p><ul><li>目标：设置API密钥等配置</li><li>位置：项目目录</li><li>操作：复制环境变量模板并编辑</li><li>命令：<code>cp .env.example .env</code></li><li>成功标志：.env文件创建成功</li><li>失败处理：确认文件存在</li></ul><p><strong>步骤3：启动服务</strong></p><ul><li>目标：启动所有服务容器</li><li>位置：项目目录</li><li>命令：<code>docker compose up -d</code></li><li>成功标志：所有容器启动成功</li><li>失败处理：检查Docker服务是否运行</li></ul><p><strong>步骤4：访问Web界面</strong></p><ul><li>目标：打开PentAGI Web界面</li><li>位置：浏览器</li><li>操作：访问 <a href="http://localhost:8080" target="_blank" rel="noreferrer">http://localhost:8080</a></li><li>成功标志：Web界面正常显示</li><li>失败处理：检查端口是否被占用</li></ul><h3 id="安装成功验证" tabindex="-1">安装成功验证 <a class="header-anchor" href="#安装成功验证" aria-label="Permalink to “安装成功验证”">​</a></h3><ul><li>所有Docker容器正常运行（docker ps查看）</li><li>Web界面可以正常访问</li><li>可以创建新的渗透测试任务</li></ul><h3 id="常见错误排查" tabindex="-1">常见错误排查 <a class="header-anchor" href="#常见错误排查" aria-label="Permalink to “常见错误排查”">​</a></h3><ol><li><p><strong>Docker容器启动失败</strong></p><ul><li>可能原因：端口冲突或资源不足</li><li>解决步骤：检查端口占用，增加系统资源</li></ul></li><li><p><strong>API连接失败</strong></p><ul><li>可能原因：API密钥未配置或无效</li><li>解决步骤：检查.env文件中的API密钥配置</li></ul></li><li><p><strong>Web界面无法访问</strong></p><ul><li>可能原因：端口被占用或防火墙阻止</li><li>解决步骤：修改端口映射或开放防火墙端口</li></ul></li></ol><h3 id="官方文档" tabindex="-1">官方文档 <a class="header-anchor" href="#官方文档" aria-label="Permalink to “官方文档”">​</a></h3><ul><li><a href="https://github.com/vxcontrol/pentagi" target="_blank" rel="noreferrer">PentAGI Documentation</a> <a href="/网络环境.html">海外网络环境配置 →</a></li></ul>',37)]))}const b=l(o,[["render",t]]);export{g as __pageData,b as default};
